  console.log("Count:", i);
}
```
:::

# Writing Functions

A function packages up reusable logic.

```js
function greet(name) {
  return "Hello, " + name + "!";
}

console.log(greet("Dexterity"));
```

Arrow functions are a shorter, modern syntax:

```js
const add = (a, b) => a + b;
```

:::try
